// Splits the single API response's items array into one n8n item
// per document, so the Postgres node can process each independently.
const items = $json.items || [];
return items.map(item => ({ json: item }));

// Chunks new documents into multiple messages if needed, rather than
// risking one oversized message — Telegram rejects anything over 4096
// characters, which the very first run (everything is 'new') will hit
// even though normal daily runs (0-3 new items) never would.
const items = $input.all().map(i => i.json);
if (items.length === 0) return [];

const MAX_CHARS = 3500; // safety margin under Telegram's 4096 limit
const chunks = [];
let currentLines = [];
let currentLength = 0;

for (const item of items) {
  const line = `📄 ${item.title}\n${item.url}`;
  if (currentLength + line.length + 2 > MAX_CHARS && currentLines.length > 0) {
    chunks.push(currentLines);
    currentLines = [];
    currentLength = 0;
  }
  currentLines.push(line);
  currentLength += line.length + 2;
}
if (currentLines.length > 0) chunks.push(currentLines);

return chunks.map((lines, idx) => {
  const header = chunks.length > 1
    ? `New CBN publications (part ${idx + 1}/${chunks.length}):\n\n`
    : `New CBN publication${items.length > 1 ? 's' : ''} (${items.length}):\n\n`;
  return { json: { text: header + lines.join('\n\n') } };
});

// Separate branch, decoupled from Telegram sending entirely — collects
// every new document's id into one item, regardless of how many chunks
// the alert message above got split into. This sidesteps the exact
// cross-node reference problem we hit in Project 2 (a node downstream
// of Telegram can't reliably read pre-Telegram data), by simply not
// routing through Telegram at all for this step.
const items = $input.all().map(i => i.json);
return [{ json: { ids: items.map(i => i.id) } }];

